using Warehouse;

namespace InventoryTracker.Tests;

[TestClass]
public class StockLevelTests
{
    [TestMethod]
    public void GetStockLevel_NewSku_ReturnsZero()
    {
        var tracker = new InventoryTracker();

        int level = tracker.GetStockLevel("SKU-001");

        Assert.AreEqual(0, level);
    }

    [TestMethod]
    public void AddStock_PositiveQuantity_IncreasesStockLevel()
    {
        var tracker = new InventoryTracker();

        tracker.AddStock("SKU-001", 50);

        Assert.AreEqual(50, tracker.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void AddStock_CalledMultipleTimes_AccumulatesQuantity()
    {
        var tracker = new InventoryTracker();

        tracker.AddStock("SKU-001", 30);
        tracker.AddStock("SKU-001", 20);

        Assert.AreEqual(50, tracker.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void AddStock_DifferentSkus_TrackedIndependently()
    {
        var tracker = new InventoryTracker();

        tracker.AddStock("SKU-001", 10);
        tracker.AddStock("SKU-002", 25);

        Assert.AreEqual(10, tracker.GetStockLevel("SKU-001"));
        Assert.AreEqual(25, tracker.GetStockLevel("SKU-002"));
    }

    [TestMethod]
    public void AddStock_ZeroQuantity_DoesNotChangeLevel()
    {
        var tracker = new InventoryTracker();
        tracker.AddStock("SKU-001", 10);

        tracker.AddStock("SKU-001", 0);

        Assert.AreEqual(10, tracker.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void AddStock_NegativeQuantity_ThrowsArgumentException()
    {
        var tracker = new InventoryTracker();

        Assert.ThrowsException<ArgumentException>(() => tracker.AddStock("SKU-001", -5));
    }

    [TestMethod]
    public void AddStock_NullSku_ThrowsArgumentNullException()
    {
        var tracker = new InventoryTracker();

        Assert.ThrowsException<ArgumentNullException>(() => tracker.AddStock(null!, 10));
    }

    [TestMethod]
    public void GetStockLevel_NullSku_ThrowsArgumentNullException()
    {
        var tracker = new InventoryTracker();

        Assert.ThrowsException<ArgumentNullException>(() => tracker.GetStockLevel(null!));
    }
}

[TestClass]
public class ReorderAlertTests
{
    [TestMethod]
    public void NeedsReorder_StockAboveThreshold_ReturnsFalse()
    {
        var tracker = new InventoryTracker();
        tracker.AddStock("SKU-001", 100);

        bool result = tracker.NeedsReorder("SKU-001");

        Assert.IsFalse(result);
    }

    [TestMethod]
    public void NeedsReorder_StockAtZero_ReturnsTrue()
    {
        var tracker = new InventoryTracker();

        bool result = tracker.NeedsReorder("SKU-001");

        Assert.IsTrue(result);
    }

    [TestMethod]
    public void NeedsReorder_StockBelowThreshold_ReturnsTrue()
    {
        var tracker = new InventoryTracker();
        tracker.AddStock("SKU-001", 5);

        bool result = tracker.NeedsReorder("SKU-001");

        Assert.IsTrue(result);
    }

    [TestMethod]
    public void NeedsReorder_NullSku_ThrowsArgumentNullException()
    {
        var tracker = new InventoryTracker();

        Assert.ThrowsException<ArgumentNullException>(() => tracker.NeedsReorder(null!));
    }

    [TestMethod]
    public void NeedsReorder_UnknownSku_ReturnsTrue()
    {
        var tracker = new InventoryTracker();

        bool result = tracker.NeedsReorder("UNKNOWN");

        Assert.IsTrue(result);
    }
}

[TestClass]
public class WarehouseTransferTests
{
    [TestMethod]
    public void Transfer_ValidQuantity_DeductsFromSource()
    {
        var source = new InventoryTracker();
        var destination = new InventoryTracker();
        source.AddStock("SKU-001", 100);

        TransferStock(source, destination, "SKU-001", 40);

        Assert.AreEqual(60, source.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void Transfer_ValidQuantity_AddsToDestination()
    {
        var source = new InventoryTracker();
        var destination = new InventoryTracker();
        source.AddStock("SKU-001", 100);

        TransferStock(source, destination, "SKU-001", 40);

        Assert.AreEqual(40, destination.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void Transfer_EntireStock_LeavesSourceAtZero()
    {
        var source = new InventoryTracker();
        var destination = new InventoryTracker();
        source.AddStock("SKU-001", 50);

        TransferStock(source, destination, "SKU-001", 50);

        Assert.AreEqual(0, source.GetStockLevel("SKU-001"));
        Assert.AreEqual(50, destination.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void Transfer_ExceedsSourceStock_ThrowsInvalidOperationException()
    {
        var source = new InventoryTracker();
        var destination = new InventoryTracker();
        source.AddStock("SKU-001", 10);

        Assert.ThrowsException<InvalidOperationException>(
            () => TransferStock(source, destination, "SKU-001", 20));
    }

    [TestMethod]
    public void Transfer_ZeroQuantity_ThrowsArgumentException()
    {
        var source = new InventoryTracker();
        var destination = new InventoryTracker();
        source.AddStock("SKU-001", 10);

        Assert.ThrowsException<ArgumentException>(
            () => TransferStock(source, destination, "SKU-001", 0));
    }

    [TestMethod]
    public void Transfer_DestinationAlreadyHasStock_Accumulates()
    {
        var source = new InventoryTracker();
        var destination = new InventoryTracker();
        source.AddStock("SKU-001", 100);
        destination.AddStock("SKU-001", 20);

        TransferStock(source, destination, "SKU-001", 30);

        Assert.AreEqual(70, source.GetStockLevel("SKU-001"));
        Assert.AreEqual(50, destination.GetStockLevel("SKU-001"));
    }

    /// <summary>
    /// Helper that simulates a warehouse-to-warehouse transfer.
    /// Replace with the real transfer API once implemented on InventoryTracker.
    /// </summary>
    private static void TransferStock(
        InventoryTracker source, InventoryTracker destination, string sku, int quantity)
    {
        if (quantity <= 0)
            throw new ArgumentException("Transfer quantity must be positive.", nameof(quantity));

        int available = source.GetStockLevel(sku);
        if (quantity > available)
            throw new InvalidOperationException(
                $"Insufficient stock. Available: {available}, requested: {quantity}.");

        source.AddStock(sku, -quantity);
        destination.AddStock(sku, quantity);
    }
}

